### Building an LLM Client Wrapper

```python
class UnifiedLLMClient:
    """
    Unified interface for multiple LLM providers.
    """

    def __init__(self, provider="openai", model="gpt-4"):
        self.provider = provider
        self.model = model
        self.client = self._init_client()

    def _init_client(self):
        if self.provider == "openai":
            return OpenAI()
        elif self.provider == "anthropic":
            return anthropic.Anthropic()
        else:
            raise ValueError(f"Unknown provider: {self.provider}")

    def generate(
        self,
        prompt: str,
        system: str = None,
        temperature: float = 0.7,
        max_tokens: int = 1000,
        stream: bool = False
    ):
        if self.provider == "openai":
            messages = []
            if system:
                messages.append({"role": "system", "content": system})
            messages.append({"role": "user", "content": prompt})

            response = self.client.chat.completions.create(
                model=self.model,
                messages=messages,
                temperature=temperature,
                max_tokens=max_tokens,
                stream=stream
            )

            if stream:
                return self._stream_openai(response)
            return response.choices[0].message.content

        elif self.provider == "anthropic":
            response = self.client.messages.create(
                model=self.model,
                max_tokens=max_tokens,
                system=system,
                messages=[{"role": "user", "content": prompt}],
                temperature=temperature
            )
            return response.content[0].text

    def _stream_openai(self, stream):
        for chunk in stream:
            if chunk.choices[0].delta.content:
                yield chunk.choices[0].delta.content
```

### Error Handling and Retries

```python
from tenacity import retry, stop_after_attempt, wait_exponential
import openai

@retry(
    stop=stop_after_attempt(3),
    wait=wait_exponential(multiplier=1, min=4, max=10),
    retry=lambda e: isinstance(e, openai.RateLimitError)
)
def generate_with_retry(prompt: str):
    try:
        return client.chat.completions.create(
            model="gpt-4",
            messages=[{"role": "user", "content": prompt}]
        )
    except openai.APIConnectionError as e:
        logger.error(f"Connection error: {e}")
        raise
    except openai.RateLimitError as e:
        logger.warning(f"Rate limit hit, retrying...")
        raise
    except openai.APIStatusError as e:
        logger.error(f"API error: {e}")
        raise
```

### Rate Limiting and Cost Management

```python
class RateLimitedLLM:
    def __init__(self, rpm_limit=60, token_limit=90000):
        self.rpm_limit = rpm_limit
        self.token_limit = token_limit
        self.request_times = []
        self.token_usage = []

    def generate(self, prompt, **kwargs):
        self._wait_if_needed()

        response = llm.generate(prompt, **kwargs)

        self.request_times.append(time.time())
        self.token_usage.append(response.usage.total_tokens)

        return response

    def _wait_if_needed(self):
        now = time.time()

        # Clean old requests
        self.request_times = [t for t in self.request_times if now - t < 60]

        if len(self.request_times) >= self.rpm_limit:
            wait_time = 60 - (now - self.request_times[0])
            time.sleep(wait_time)
```

