## Agent Memory Architecture

### Types of Memory

#### 1. Short-Term Memory (Context)
```python
class ShortTermMemory:
    """
    Temporary storage in context window.
    """

    def __init__(self, max_tokens: int = 4000):
        self.messages = []
        self.max_tokens = max_tokens

    def add(self, role: str, content: str):
        self.messages.append({"role": role, "content": content})
        self.trim_if_needed()

    def get_context(self) -> List[dict]:
        return self.messages

    def trim_if_needed(self):
        while self.count_tokens() > self.max_tokens:
            # Remove oldest non-system message
            for i, msg in enumerate(self.messages):
                if msg['role'] != 'system':
                    self.messages.pop(i)
                    break
```

#### 2. Long-Term Memory (Vector Store)
```python
class LongTermMemory:
    """
    Persistent storage using vector embeddings.
    """

    def __init__(self, embedding_model, vector_db):
        self.embedder = embedding_model
        self.db = vector_db

    def store(self, content: str, metadata: dict = None):
        """Store a memory."""
        embedding = self.embedder.embed(content)
        memory_id = str(uuid.uuid4())

        self.db.upsert(
            id=memory_id,
            embedding=embedding,
            metadata={
                "content": content,
                "timestamp": datetime.now().isoformat(),
                **(metadata or {})
            }
        )

    def recall(self, query: str, k: int = 5) -> List[dict]:
        """Retrieve relevant memories."""
        query_embedding = self.embedder.embed(query)
        results = self.db.search(query_embedding, k)

        return [
            {"content": r.metadata['content'], "score": r.score}
            for r in results
        ]
```

#### 3. Working Memory (Scratchpad)
```python
class WorkingMemory:
    """
    Temporary scratchpad for complex tasks.
    """

    def __init__(self):
        self.data = {}
        self.history = []

    def set(self, key: str, value: Any):
        self.data[key] = value
        self.history.append({
            'action': 'set',
            'key': key,
            'value': value,
            'timestamp': datetime.now()
        })

    def get(self, key: str) -> Any:
        return self.data.get(key)

    def to_context(self) -> str:
        """Format for inclusion in prompts."""
        lines = ["Current state:"]
        for key, value in self.data.items():
            lines.append(f"  {key}: {value}")
        return '\n'.join(lines)
```

### Memory Management Strategies

#### Sliding Window
```python
class SlidingWindowMemory:
    """
    Keep last N interactions.
    """

    def __init__(self, window_size: int = 10):
        self.window_size = window_size
        self.messages = []

    def add(self, message: dict):
        self.messages.append(message)
        if len(self.messages) > self.window_size:
            self.messages.pop(0)
```

#### Summary-Based
```python
class SummaryMemory:
    """
    Summarize old conversations.
    """

    def __init__(self, llm, max_before_summary: int = 10):
        self.llm = llm
        self.max_before_summary = max_before_summary
        self.recent = []
        self.summary = ""

    def add(self, message: dict):
        self.recent.append(message)

        if len(self.recent) > self.max_before_summary:
            self.summarize_old()

    def summarize_old(self):
        to_summarize = self.recent[:-self.max_before_summary//2]
        self.recent = self.recent[-self.max_before_summary//2:]

        prompt = f"Summarize this conversation:\n{to_summarize}"
        new_summary = self.llm.generate(prompt)

        self.summary = f"Previous context: {new_summary}\n\n{self.summary}"
```

#### Entity-Based
```python
class EntityMemory:
    """
    Track entities and their attributes.
    """

    def __init__(self):
        self.entities = {}  # {entity_name: {attribute: value}}

    def update(self, entity: str, attributes: dict):
        if entity not in self.entities:
            self.entities[entity] = {}
        self.entities[entity].update(attributes)

    def get(self, entity: str) -> dict:
        return self.entities.get(entity, {})

    def to_context(self) -> str:
        lines = ["Known entities:"]
        for entity, attrs in self.entities.items():
            attrs_str = ', '.join(f"{k}: {v}" for k, v in attrs.items())
            lines.append(f"  {entity}: {attrs_str}")
        return '\n'.join(lines)
```

### Complete Memory System

```python
class AgentMemory:
    """
    Unified memory system for agents.
    """

    def __init__(self, llm, embedding_model, vector_db):
        self.short_term = ShortTermMemory(max_tokens=4000)
        self.long_term = LongTermMemory(embedding_model, vector_db)
        self.working = WorkingMemory()
        self.summary = SummaryMemory(llm)

    def remember(self, content: str, importance: float = 0.5):
        """Store information in appropriate memory."""
        if importance > 0.7:
            # Important вҶ’ long-term
            self.long_term.store(content)

        # Always add to short-term
        self.short_term.add("assistant", content)

    def recall(self, query: str) -> str:
        """Retrieve relevant memories."""
        # Get from long-term
        long_term = self.long_term.recall(query, k=3)

        # Get summary
        summary = self.summary.summary

        # Get working state
        working = self.working.to_context()

        # Combine
        context_parts = []
        if summary:
            context_parts.append(f"Context: {summary}")
        if long_term:
            context_parts.append("Relevant memories:")
            for mem in long_term:
                context_parts.append(f"  - {mem['content']}")
        if working:
            context_parts.append(working)

        return '\n'.join(context_parts)
```

### Memory in Agent Loop

```python
class AgentWithMemory:
    def __init__(self, llm, memory: AgentMemory):
        self.llm = llm
        self.memory = memory

    def run(self, query: str):
        # Retrieve relevant memories
        context = self.memory.recall(query)

        # Build prompt with memory
        prompt = f"""
{context}

User: {query}

Think about what to do.
"""

        # Get response
        response = self.llm.generate(prompt)

        # Store important parts
        self.memory.remember(response, importance=0.5)

        return response
```

