### Complete Function Calling Loop

```python
class FunctionCaller:
    def __init__(self, client, functions: dict):
        self.client = client
        self.functions = functions
        self.function_definitions = self._build_definitions()

    def run(self, user_message: str) -> str:
        messages = [{"role": "user", "content": user_message}]

        while True:
            response = self.client.chat.completions.create(
                model="gpt-4-turbo-preview",
                messages=messages,
                functions=self.function_definitions,
                function_call="auto"
            )

            message = response.choices[0].message
            messages.append(message)

            # Check if done
            if not message.function_call:
                return message.content

            # Execute function
            function_name = message.function_call.name
            arguments = json.loads(message.function_call.arguments)

            result = self.execute_function(function_name, arguments)

            # Add result to messages
            messages.append({
                "role": "function",
                "name": function_name,
                "content": json.dumps(result)
            })

    def execute_function(self, name: str, args: dict):
        if name in self.functions:
            return self.functions[name](**args)
        else:
            return {"error": f"Unknown function: {name}"}

    def _build_definitions(self):
        # Convert function objects to schema
        pass
```

