## Tool Design Principles

### What Makes a Good Tool?

1. **Clear Purpose**: Single, well-defined responsibility
2. **Simple Interface**: Minimal required parameters
3. **Robust**: Handles errors gracefully
4. **Documented**: Clear descriptions for LLM

### Tool Framework

```python
from dataclasses import dataclass
from typing import Callable, Any
import json

@dataclass
class Tool:
    name: str
    description: str
    parameters: dict
    function: Callable

    def to_schema(self) -> dict:
        """Convert to LLM-compatible schema."""
        return {
            "name": self.name,
            "description": self.description,
            "parameters": self.parameters
        }

    def execute(self, **kwargs) -> Any:
        """Execute the tool with validation."""
        # Validate parameters
        self.validate(kwargs)

        # Execute
        try:
            result = self.function(**kwargs)
            return {"success": True, "result": result}
        except Exception as e:
            return {"success": False, "error": str(e)}

    def validate(self, params: dict):
        """Validate parameters against schema."""
        required = self.parameters.get("required", [])
        for param in required:
            if param not in params:
                raise ValueError(f"Missing required parameter: {param}")
```

### Tool Builder Pattern

```python
class ToolBuilder:
    def __init__(self, name: str):
        self.name = name
        self.description = ""
        self.params = {"type": "object", "properties": {}, "required": []}
        self.function = None

    def describe(self, description: str) -> 'ToolBuilder':
        self.description = description
        return self

    def param(self, name: str, type: str, description: str, 
              required: bool = True, enum: list = None, default = None):
        self.params["properties"][name] = {
            "type": type,
            "description": description
        }
        if enum:
            self.params["properties"][name]["enum"] = enum
        if default is not None:
            self.params["properties"][name]["default"] = default
        if required:
            self.params["required"].append(name)
        return self

    def implement(self, func: Callable) -> 'ToolBuilder':
        self.function = func
        return self

    def build(self) -> Tool:
        return Tool(
            name=self.name,
            description=self.description,
            parameters=self.params,
            function=self.function
        )

# Usage
weather_tool = (ToolBuilder("get_weather")
    .describe("Get current weather for a location")
    .param("location", "string", "City and country")
    .param("unit", "string", "Temperature unit", 
           enum=["celsius", "fahrenheit"], default="celsius")
    .implement(get_weather_data)
    .build())
```

