class CompositeTool(Tool):
    """Tool composed of multiple tools."""

    def __init__(self, name: str, description: str, subtools: List[Tool]):
        self.subtools = subtools
        super().__init__(
            name=name,
            description=description,
            parameters=self._merge_parameters(),
            function=self._composite_function
        )

    def _merge_parameters(self) -> dict:
        """Merge parameters from all subtools."""
        merged = {"type": "object", "properties": {}, "required": []}

        for tool in self.subtools:
            merged["properties"].update(tool.parameters["properties"])
            merged["required"].extend(tool.parameters.get("required", []))

        return merged

    async def _composite_function(self, **kwargs):
        """Execute all subtools."""
        results = []
        for tool in self.subtools:
            # Extract relevant params for this tool
            tool_params = self._extract_params(tool, kwargs)
            result = await tool.execute(**tool_params)
            results.append(result)

        return self._merge_results(results)
