class ToolValidator:
    """Validate tool calls for safety."""

    def __init__(self):
        self.rate_limits = {}
        self.banned_params = {}

    def validate(self, tool_name: str, params: dict) -> tuple[bool, str]:
        """Validate tool call."""

        # Check rate limits
        if not self.check_rate_limit(tool_name):
            return False, "Rate limit exceeded"

        # Check for banned parameters
        if tool_name in self.banned_params:
            for banned in self.banned_params[tool_name]:
                if banned in params:
                    return False, f"Parameter '{banned}' is not allowed"

        # Validate parameter values
        if not self.validate_params(tool_name, params):
            return False, "Invalid parameters"

        return True, "OK"

    def check_rate_limit(self, tool_name: str) -> bool:
        """Check if rate limit allows execution."""
        key = f"{tool_name}:{datetime.now().minute}"
        self.rate_limits[key] = self.rate_limits.get(key, 0) + 1
        return self.rate_limits[key] < 10  # 10 calls per minute
