    def __init__(self):
        self.sessions = {}  # session_id -> {tool_name -> state}

    def execute(self, session_id: str, tool_name: str, **kwargs):
        # Get or create session state
        if session_id not in self.sessions:
            self.sessions[session_id] = {}

        session_tools = self.sessions[session_id]

        # Restore tool state
        if tool_name in session_tools:
            kwargs['_state'] = session_tools[tool_name]

        # Execute
        result = self.tools[tool_name].execute(**kwargs)

        # Save state
        if '_state' in result:
            session_tools[tool_name] = result.pop('_state')

