### Workflow Engine

```python
from enum import Enum
from dataclasses import dataclass

class StepStatus(Enum):
    PENDING = "pending"
    RUNNING = "running"
    COMPLETED = "completed"
    FAILED = "failed"

@dataclass
class WorkflowStep:
    name: str
    service: Service
    dependencies: List[str]
    status: StepStatus = StepStatus.PENDING
    result: dict = None

class WorkflowEngine:
    """
    Execute complex workflows with dependencies.
    """

    def __init__(self):
        self.steps = {}
        self.results = {}

    def add_step(self, name: str, service: Service, dependencies: List[str] = None):
        self.steps[name] = WorkflowStep(
            name=name,
            service=service,
            dependencies=dependencies or []
        )

    async def execute(self, input_data: dict) -> dict:
        """Execute workflow respecting dependencies."""
        while not self.is_complete():
            # Find ready steps
            ready = self.get_ready_steps()

            if not ready:
                if not self.is_complete():
                    raise RuntimeError("Deadlock detected")
                break

            # Execute ready steps
            tasks = [self.execute_step(step, input_data) for step in ready]
            await asyncio.gather(*tasks)

        return self.results

    def get_ready_steps(self) -> List[WorkflowStep]:
        """Get steps ready to execute."""
        ready = []
        for step in self.steps.values():
            if step.status != StepStatus.PENDING:
                continue

            if all(
                self.steps[dep].status == StepStatus.COMPLETED
                for dep in step.dependencies
            ):
                ready.append(step)

        return ready

    async def execute_step(self, step: WorkflowStep, input_data: dict):
        """Execute a single step."""
        step.status = StepStatus.RUNNING

        try:
            # Gather inputs from dependencies
            step_input = {**input_data}
            for dep in step.dependencies:
                step_input.update(self.results.get(dep, {}))

            # Execute
            result = await step.service.process(step_input)
            step.result = result
            self.results[step.name] = result
            step.status = StepStatus.COMPLETED
        except Exception as e:
            step.status = StepStatus.FAILED
            self.results[step.name] = {"error": str(e)}
            raise
