### Service Mesh Pattern

```python
class ServiceMesh:
    """
    Manage multiple services with discovery and routing.
    """

    def __init__(self):
        self.services = {}
        self.middlewares = []

    def register(self, name: str, service: Service):
        self.services[name] = service

    def add_middleware(self, middleware: Callable):
        self.middlewares.append(middleware)

    async def call(self, service_name: str, method: str, **kwargs):
        """Call service with middleware chain."""
        service = self.services.get(service_name)
        if not service:
            raise ValueError(f"Unknown service: {service_name}")

        # Build middleware chain
        handler = getattr(service, method)
        for middleware in reversed(self.middlewares):
            handler = middleware(handler)

        return await handler(**kwargs)

# Middleware examples
async def logging_middleware(handler):
    async def wrapper(*args, **kwargs):
        logger.info(f"Calling {handler.__name__}")
        result = await handler(*args, **kwargs)
        logger.info(f"Completed {handler.__name__}")
        return result
    return wrapper

async def retry_middleware(max_retries=3):
    async def middleware(handler):
        async def wrapper(*args, **kwargs):
            for attempt in range(max_retries):
                try:
                    return await handler(*args, **kwargs)
                except Exception as e:
                    if attempt == max_retries - 1:
                        raise
                    await asyncio.sleep(2 ** attempt)
        return wrapper
    return middleware
