class DataPipeline:
    """
    Orchestrate data through transformations.
    """

    def __init__(self):
        self.stages = []

    def source(self, fetcher: Callable):
        self.stages.append(('source', fetcher))
        return self

    def transform(self, transformer: Callable):
        self.stages.append(('transform', transformer))
        return self

    def sink(self, writer: Callable):
        self.stages.append(('sink', writer))
        return self

    async def execute(self):
        data = None

        for stage_type, stage_func in self.stages:
            if stage_type == 'source':
                data = await stage_func()
            elif stage_type == 'transform':
                if isinstance(data, list):
                    data = [await stage_func(item) for item in data]
                else:
                    data = await stage_func(data)
            elif stage_type == 'sink':
                await stage_func(data)

        return data

